VALUES
  ('real-estate-moex-01144', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其所有土地出租予乙建築房屋。下列敘述何者錯誤？', '["契約成立後，乙得請求甲為地上權之登記", "乙將房屋所有權移轉予丙時，原基地租賃契約對於丙仍繼續存在", "乙出賣房屋時，甲無依同樣條件優先承買之權利", "甲、乙得約定由乙負擔就土地應納之一切稅捐"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01145', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙、丙三人分別共有一筆A土地。三人就A地約定各自得使用之特定部分，且於二十年內不得請求 分割。下列敘述何者最正確？', '["如甲使用部分在約定不得請求分割期間內被徵收，甲仍得隨時請求分割", "不得分割之約定逾五年，無效。三人應重新約定", "不得分割之約定逾五年，應縮短為五年", "於約定不得請求分割期間內，任一共有人皆不得處分其應有部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01146', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以其土地設定地上權於乙後，乙以該地上權設定抵押權於丙。下列敘述何者最正確？', '["原則上如乙未得甲之同意，丙所設定之抵押權無效", "如乙繼承甲之土地，地上權因混同而消滅", "非得丙之同意，乙不得拋棄其地上權", "甲不須乙、丙同意，得自由拋棄其土地所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01147', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以其土地設定地上權於乙。下列敘述何者最正確？', '["定有期限之地上權原則上不因建築物於所定期限內滅失而消滅", "甲、乙間不得設定未定有期限之地上權", "甲、乙間不得設定未定有地租之地上權", "因不可抗力致妨礙土地之使用時，乙得請求減免租金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01148', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲懷胎乙五個月時，其丈夫丙因病過世，留下一棟房屋與現金200萬元之遺產，下列敘述何者最正確？', '["乙尚未出生，不具有權利能力，不得繼承丙之遺產", "乙雖尚未出生，但關於利益之享有具有部分行為能力，得繼承丙之遺產", "乙以將來非死產者為限，關於個人利益之保護享有行為能力，在出生後得溯及繼承開始時繼承丙之遺產", "乙以將來非死產者為限，關於個人利益之保護享有權利能力，得繼承丙之遺產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01149', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲分別於乙、丙所有之不動產設定普通抵押權，以擔保甲對乙之債權。下列敘述何者最正確？', '["甲向丙請求清償債務時，丙得主張先訴抗辯權", "即使甲對乙之債權已因時效而消滅，甲仍得於消滅時效完成後五年內實行對丙之抵押權", "甲僅得先對乙之不動產實行抵押權", "甲實行對丙之抵押權後，丙不得向乙求償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01150', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以其對乙尚未屆清償期之金錢債權設定權利質權於丙，以擔保丙對甲之金錢債權，並於設定時即通知 乙。下列敘述何者最正確？', '["該權利質權之設定，未得乙之同意，無效", "乙得以於受通知後始對甲取得之金錢債權，對丙主張抵銷", "乙得以於受通知時對甲之已屆清償期之金錢債權，對丙主張抵銷", "該權利質權之設定，須由甲、丙共同通知乙，始對乙生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01151', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於法定夫妻財產制，下列敘述何者錯誤？', '["無論是婚前財產或婚後財產，由夫妻各自所有", "夫或妻婚前財產，於婚姻關係存續中所生之孳息，推定為婚後財產", "夫或妻各自管理、使用、收益及處分其財產", "夫妻因判決而離婚者，其現存婚後財產之價值的計算，以起訴時為準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01152', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡時有遺族配偶乙，子女丙及丁，丙之子女戊。下列敘述何者最正確？', '["如繼承財產不足清償繼承債務，乙以其固有財產清償繼承債務後，不得向債權人主張不當得利返還請求權", "丙未表示是否繼承前即死亡，戊得於甲死亡後一年內，拋棄對甲之繼承", "即使丁於拋棄繼承時尚未成年，亦不得於事後撤銷拋棄之意思表示", "如丙已先於甲死亡，且丙於生前即表示拋棄繼承，則戊不得繼承甲之財產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01153', 'real-estate', 'real-estate-moex-101-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲發生車禍傷及腦部，成為植物人，下列敘述何者最正確？', '["甲成為植物人喪失權利能力", "甲雖成為植物人，但關於個人利益之享受仍具有部分權利能力", "植物人為無行為能力人，並且不具有權利能力", "甲雖成為植物人，仍具有權利能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0b25a06784a1", "answer_pdf_sha1": "8cbc71f2bc90", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
